#include<stdio.h>
#define ll long long

ll gcd(ll a, ll b) {
  return b == 0 ? a : gcd(b, a % b);
}

int main()
{
    ll n, i, j, ans=0;
    scanf("%lld", &n);
    for(i=2; i*i<=n; i++)
    {
        if(n%i==0)
        {
            ans = gcd(ans, i);
            ans = gcd(ans, n/i);
        }
    }
    ans = gcd(ans, n);
    printf("%lld\n", ans);

    return 0;
}

